prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  ?orgId
  (COUNT(DISTINCT ?model) AS ?modelCount)
WHERE {
  ?org a bboExt:Organization ;
       tai:corpusId ?corpusId ;
       tai:organizationId ?orgId .
  OPTIONAL {
    ?model a bboExt:Model ;
           tai:belongsTo ?org .
  }
  FILTER(BOUND(?orgId))
}
GROUP BY ?orgId
HAVING (COUNT(DISTINCT ?model) = {
  SELECT (COUNT(DISTINCT ?m0) AS ?targetCount) WHERE {
    ?org0 a bboExt:Organization ;
          tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
    OPTIONAL { ?m0 a bboExt:Model ; tai:belongsTo ?org0 . }
  }
})
ORDER BY ?orgId
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?orgId
  ?modelCount
WHERE {
  {
    SELECT (COUNT(DISTINCT ?m0) AS ?targetCount) WHERE {
      ?org0 a bboExt:Organization ;
            tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
      OPTIONAL { ?m0 a bboExt:Model ; tai:belongsTo ?org0 . }
    }
  }

  ?org a bboExt:Organization ;
       tai:organizationId ?orgId .

  OPTIONAL { ?model a bboExt:Model ; tai:belongsTo ?org . }

  BIND(COUNT(DISTINCT ?model) AS ?modelCount)
  FILTER(?modelCount = ?targetCount)
}
GROUP BY ?orgId ?modelCount
ORDER BY ?orgId
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?orgId
  ?modelCount
WHERE {
  {
    SELECT (COUNT(DISTINCT ?m0) AS ?targetCount) WHERE {
      ?org0 a bboExt:Organization ;
            tai:organizationId "4d36ddb24c9e4cc38572abbd646c1e58" .
      OPTIONAL { ?m0 a bboExt:Model ; tai:belongsTo ?org0 . }
    }
  }

  {
    SELECT ?orgId (COUNT(DISTINCT ?model) AS ?modelCount) WHERE {
      ?org a bboExt:Organization ;
           tai:organizationId ?orgId .
      OPTIONAL { ?model a bboExt:Model ; tai:belongsTo ?org . }
    }
    GROUP BY ?orgId
  }

  FILTER(?modelCount = ?targetCount)
}
ORDER BY ?orgId
LIMIT 25
